{
  "uiTreePath": ".arkpilot/designs/ui-tree.json",
  "protocolVersion": "arkpilot-a2ui/v2",
  "appName": "平安扣 Pinankou",
  "dataModel": {
    "entities": {
      "Matter": {
        "fields": {
          "id": "string",
          "title": "string",
          "category": "MatterCategory",
          "location": "string",
          "description": "string",
          "createdAt": "string (ISO8601)"
        },
        "binding": "/matters",
        "persistence": "durable (local preferences JSON)",
        "seed": "none — first-run real-empty"
      },
      "Risk": {
        "fields": {
          "id": "string",
          "title": "string",
          "location": "string",
          "severity": "RiskSeverity (low|medium|high|critical)",
          "responsible": "string",
          "deadline": "string (ISO8601 date, optional)",
          "status": "RiskStatus (open|in-progress|closed)",
          "description": "string",
          "createdAt": "string (ISO8601)"
        },
        "binding": "/risks",
        "persistence": "durable",
        "seed": "none"
      },
      "Contact": {
        "fields": {
          "id": "string",
          "name": "string",
          "role": "string",
          "phone": "string",
          "medicalNote": "string"
        },
        "binding": "/contacts",
        "persistence": "durable",
        "seed": "none"
      },
      "PatrolRoute": {
        "fields": {
          "id": "string",
          "name": "string",
          "checkpoints": "Checkpoint[]"
        },
        "binding": "/patrol/routes",
        "persistence": "durable",
        "seed": "none — on-device route creation"
      },
      "Checkpoint": {
        "fields": {
          "id": "string",
          "name": "string",
          "status": "CheckpointStatus (pending|pass|fail)",
          "note": "string"
        },
        "binding": "/patrol/checkpoints"
      },
      "PatrolSession": {
        "fields": {
          "id": "string",
          "routeId": "string",
          "routeName": "string",
          "startedAt": "string (ISO8601)",
          "completedAt": "string (ISO8601, optional)",
          "progress": "number (0-100)",
          "checkpoints": "Checkpoint[]"
        },
        "binding": "/patrol/sessions",
        "persistence": "durable"
      },
      "Settings": {
        "fields": {
          "profileName": "string",
          "profileRole": "string",
          "notificationsEnabled": "boolean"
        },
        "binding": "/settings/*",
        "persistence": "durable"
      }
    },
    "computedState": {
      "/stats/openRisks": "count(risks where status!=closed)",
      "/stats/overdue": "count(risks where deadline<today and status!=closed)",
      "/stats/todayPatrols": "count(sessions completed today)",
      "/stats/closedThisWeek": "count(risks closed in last 7 days)",
      "/patrol/progress": "percent of checkpoints with status!=pending in active session",
      "/stats/weeklyTrend": "per-week reported/closed counts over rolling 7-day buckets grouped by calendar week",
      "/stats/categoryDistribution": "matter+risk counts grouped by category",
      "/stats/patrolCompletion": "percent of checkpoints marked pass or fail across completed sessions",
      "/stats/overdueRatio": "overdue / total open risks (0 when no open risks)"
    }
  },
  "services": [
    {
      "name": "LocalRepository",
      "role": "durable local persistence + in-memory collections",
      "api": "@kit.ArkData preferences (JSON blobs per collection)",
      "boundary": "CRUD only; no UI/reactivity; async init(context) then sync memory access",
      "fallback": "if preferences unavailable, fall back to in-memory only and log"
    },
    {
      "name": "StatsService",
      "role": "pure derivation of dashboard/statistics values from repository state",
      "boundary": "no side effects, no persistence"
    },
    {
      "name": "AppController",
      "role": "singleton view-model / state machine; owns repository + stats; exposes ui-behavior event methods and reactive getters",
      "boundary": "global; consumed by pages in visual phase"
    }
  ],
  "stateMachine": {
    "states": {
      "app.idle": "no modal open, tab surface active",
      "matter.form.open": "add-edit-matter sheet visible (create or edit by pendingMatterId)",
      "risk.form.open": "add-edit-risk sheet visible (create or edit by pendingRiskId)",
      "contact.form.open": "add-edit-contact sheet visible (create or edit by pendingContactId)",
      "patrol.idle": "route selected or none; no active session",
      "patrol.active": "session in progress; checkpoints being marked",
      "patrol.submitted": "session completed and persisted; returns to idle"
    },
    "transitions": [
      { "from": "app.idle", "event": "open-add-matter", "to": "matter.form.open", "effect": "pendingMatterId=''" },
      { "from": "app.idle|matters", "event": "open-edit-matter", "to": "matter.form.open", "effect": "pendingMatterId=ctx.matterId" },
      { "from": "matter.form.open", "event": "save-matter", "to": "app.idle", "effect": "upsert matter (validate title), persist" },
      { "from": "matter.form.open", "event": "cancel-matter-form", "to": "app.idle", "effect": "discard draft" },
      { "from": "app.idle|risks", "event": "open-add-risk", "to": "risk.form.open", "effect": "pendingRiskId=''" },
      { "from": "app.idle|risks", "event": "open-edit-risk", "to": "risk.form.open", "effect": "pendingRiskId=ctx.riskId" },
      { "from": "risk.form.open", "event": "save-risk", "to": "app.idle", "effect": "upsert risk (validate title+severity), persist" },
      { "from": "risk.form.open", "event": "cancel-risk-form", "to": "app.idle", "effect": "discard draft" },
      { "from": "patrol.idle", "event": "select-patrol-route", "to": "patrol.idle", "effect": "selectedRouteId=ctx.routeId" },
      { "from": "patrol.idle", "event": "start-patrol", "to": "patrol.active", "effect": "new session from selected route, checkpoints reset to pending" },
      { "from": "patrol.active", "event": "checkpoint-pass|checkpoint-fail", "to": "patrol.active", "effect": "set checkpoint status, optional note, recompute progress" },
      { "from": "patrol.active", "event": "submit-patrol", "to": "patrol.submitted", "effect": "persist session, completedAt=now, then patrol.idle" },
      { "from": "risks|rectification", "event": "advance-rectification", "to": "same", "effect": "open->in-progress->closed, persist" },
      { "from": "app.idle", "event": "delete-*", "to": "app.idle", "effect": "remove entity, persist" }
    ]
  },
  "interactionFlows": [
    {
      "name": "create-safety-matter",
      "trigger": "dashboard-add-matter-button | matters-add-button | matter-empty-add-button",
      "steps": ["open-add-matter", "fill title/location/category/description", "save-matter"],
      "validation": "title required (non-empty after trim)",
      "success": "matter appears in /matters and dashboard recent list",
      "error": "invalid -> save blocked with feedback, no persistence"
    },
    {
      "name": "report-risk",
      "trigger": "dashboard-add-risk-button | risks-add-button | risk-empty-add-button",
      "steps": ["open-add-risk", "fill title/location/severity/responsible/deadline/description/status", "save-risk"],
      "validation": "title required; severity one of low|medium|high|critical",
      "success": "risk appears in /risks grouped by status; affects dashboard open/overdue stats",
      "error": "invalid -> blocked"
    },
    {
      "name": "run-patrol",
      "trigger": "dashboard-start-patrol-button | patrol surface",
      "steps": ["select-patrol-route (or create on-device)", "start-patrol", "checkpoint-pass|checkpoint-fail per checkpoint with optional note", "submit-patrol"],
      "validation": "start requires a route with >=1 checkpoint",
      "success": "session persisted; affects /stats/todayPatrols and patrolCompletion",
      "error": "submit allowed even with pending checkpoints (partial patrol recorded)"
    },
    {
      "name": "contact-emergency",
      "trigger": "contact-item-{id}-call | contact-item-{id}-message",
      "steps": ["resolve contact by id", "invoke system dialer/messaging intent with phone"],
      "fallback": "non-goal: real telephony; system intent only. Invalid phone -> feedback, no action"
    },
    {
      "name": "advance-rectification",
      "trigger": "rect-item-{id}-advance",
      "steps": ["advance status open->in-progress->closed", "persist"],
      "effect": "updates /risks/status/* lanes and dashboard closedThisWeek when reaching closed"
    },
    {
      "name": "view-statistics",
      "trigger": "dashboard-view-statistics-button | settings-statistics-button",
      "steps": ["navigate-statistics", "select-statistics-period (7d|30d)", "render weekly trend / category / patrol completion / overdue ratio"],
      "data": "derived from repository; export-statistics produces local summary text (no network)"
    }
  ],
  "testTargets": {
    "tabs": ["tab-home", "tab-matters", "tab-patrol", "tab-risks", "tab-more"],
    "assertions": [
      "dashboard-stat-open-risks", "dashboard-stat-overdue", "dashboard-stat-today-patrols",
      "dashboard-stat-closed-this-week", "patrol-progress-bar", "statistics-weekly-trend-chart",
      "statistics-category-chart", "statistics-patrol-completion-chart", "statistics-overdue-ratio-chart"
    ],
    "actions": [
      "dashboard-add-matter-button", "dashboard-add-risk-button", "dashboard-start-patrol-button",
      "matters-add-button", "matters-filter-button", "risks-add-button", "risks-filter-status",
      "patrol-start-button", "patrol-submit-button", "patrol-checkpoint-{id}-pass", "patrol-checkpoint-{id}-fail",
      "contacts-add-button", "contact-item-{id}-call", "contact-item-{id}-message",
      "rect-item-{id}-advance", "settings-export-data-button", "statistics-export-button"
    ],
    "inputs": [
      "dashboard-search-field", "matters-search-input", "risks-search-input", "contacts-search-input",
      "matter-form-title-input", "risk-form-title-input", "risk-form-severity-picker",
      "contact-form-name-input", "patrol-checkpoint-{id}-note", "settings-profile-name"
    ],
    "lists": [
      "dashboard-recent-matters-list", "dashboard-recent-risks-list", "matters-list", "risks-list",
      "patrol-checkpoint-list", "contacts-list", "rectification-open-lane",
      "rectification-progress-lane", "rectification-closed-lane"
    ],
    "emptyStates": [
      "dashboard-recent-empty", "dashboard-risks-empty", "matters-empty-state", "risks-empty-state",
      "patrol-empty-state", "contacts-empty-state", "rect-open-empty", "rect-progress-empty", "rect-closed-empty"
    ]
  },
  "changeRequests": []
}

