// Models.ets
//
// Domain model for the Pinankou safety management app.
// Shared types, enums, and pure helpers used by the repository, services,
// controller, and (later) the page/component layer.
//
// This module contains NO UI and NO persistence — it is the type-level
// contract for the headless feature logic.

// ---------- Enumerations ----------

// Safety matter category. Mirrors the categories surfaced on the dashboard
// category chart. Order is stable so it can be reused by pickers.
export enum MatterCategory {
  FireSafety = 0,
  Electrical = 1,
  Equipment = 2,
  Environment = 3,
  Personnel = 4,
  Other = 5,
}

// Risk severity, from low to critical. Stable numeric order drives chip styling.
export enum RiskSeverity {
  Low = 0,
  Medium = 1,
  High = 2,
  Critical = 3,
}

// Risk lifecycle status. Drives the rectification lanes and filters.
export enum RiskStatus {
  Open = 0,
  InProgress = 1,
  Closed = 2,
}

// Per-checkpoint result during a patrol session.
export enum CheckpointStatus {
  Pending = 0,
  Pass = 1,
  Fail = 2,
}

// ---------- Entities ----------

export interface Matter {
  id: string;
  title: string;
  category: MatterCategory;
  location: string;
  description: string;
  createdAt: string; // ISO8601
}

export interface Risk {
  id: string;
  title: string;
  location: string;
  severity: RiskSeverity;
  responsible: string;
  deadline: string; // ISO8601 date, '' when none
  status: RiskStatus;
  description: string;
  createdAt: string; // ISO8601
}

export interface Contact {
  id: string;
  name: string;
  role: string;
  phone: string;
  medicalNote: string;
}

export interface Checkpoint {
  id: string;
  name: string;
  status: CheckpointStatus;
  note: string;
}

export interface PatrolRoute {
  id: string;
  name: string;
  checkpoints: Checkpoint[];
}

export interface PatrolSession {
  id: string;
  routeId: string;
  routeName: string;
  startedAt: string; // ISO8601
  completedAt: string; // ISO8601, '' while in progress
  progress: number; // 0-100
  checkpoints: Checkpoint[];
}

export interface Settings {
  profileName: string;
  profileRole: string;
  notificationsEnabled: boolean;
}

// ---------- Option lookups (for pickers and chips) ----------

export interface EnumOption<T> {
  value: T;
  label: string;
}

export const MATTER_CATEGORY_OPTIONS: EnumOption<MatterCategory>[] = [
  { value: MatterCategory.FireSafety, label: '消防安全' },
  { value: MatterCategory.Electrical, label: '电气安全' },
  { value: MatterCategory.Equipment, label: '设备设施' },
  { value: MatterCategory.Environment, label: '环境隐患' },
  { value: MatterCategory.Personnel, label: '人员行为' },
  { value: MatterCategory.Other, label: '其他' },
];

export const RISK_SEVERITY_OPTIONS: EnumOption<RiskSeverity>[] = [
  { value: RiskSeverity.Low, label: '低' },
  { value: RiskSeverity.Medium, label: '中' },
  { value: RiskSeverity.High, label: '高' },
  { value: RiskSeverity.Critical, label: '紧急' },
];

export const RISK_STATUS_OPTIONS: EnumOption<RiskStatus>[] = [
  { value: RiskStatus.Open, label: '待处理' },
  { value: RiskStatus.InProgress, label: '整改中' },
  { value: RiskStatus.Closed, label: '已闭环' },
];

export function matterCategoryLabel(value: MatterCategory): string {
  const found: EnumOption<MatterCategory> | undefined =
    MATTER_CATEGORY_OPTIONS.find((opt: EnumOption<MatterCategory>) => opt.value === value);
  return found ? found.label : '其他';
}

export function riskSeverityLabel(value: RiskSeverity): string {
  const found: EnumOption<RiskSeverity> | undefined =
    RISK_SEVERITY_OPTIONS.find((opt: EnumOption<RiskSeverity>) => opt.value === value);
  return found ? found.label : '中';
}

export function riskStatusLabel(value: RiskStatus): string {
  const found: EnumOption<RiskStatus> | undefined =
    RISK_STATUS_OPTIONS.find((opt: EnumOption<RiskStatus>) => opt.value === value);
  return found ? found.label : '待处理';
}

export function nextRiskStatus(value: RiskStatus): RiskStatus {
  if (value === RiskStatus.Open) {
    return RiskStatus.InProgress;
  }
  if (value === RiskStatus.InProgress) {
    return RiskStatus.Closed;
  }
  return RiskStatus.Closed;
}

// ---------- Pure helpers ----------

// Deterministic-ish id generator. Uses timestamp + random suffix.
// Safe for app runtime (not the workflow sandbox).
export function genId(prefix: string): string {
  const suffix: string = Math.floor(Math.random() * 0xffffff).toString(16);
  const padded: string = suffix.length < 6 ? suffix.padStart(6, '0') : suffix;
  return `${prefix}-${Date.now().toString(36)}-${padded}`;
}

export function nowISO(): string {
  return new Date().toISOString();
}

// Today's date at local midnight as ISO, used for "completed today" checks.
export function todayStartISO(): string {
  const d: Date = new Date();
  d.setHours(0, 0, 0, 0);
  return d.toISOString();
}

// Format an ISO date for display as YYYY-MM-DD, returning '' for empty input.
export function formatDate(iso: string): string {
  if (!iso) {
    return '';
  }
  const d: Date = new Date(iso);
  if (Number.isNaN(d.getTime())) {
    return '';
  }
  const y: number = d.getFullYear();
  const m: string = (d.getMonth() + 1).toString().padStart(2, '0');
  const day: string = d.getDate().toString().padStart(2, '0');
  return `${y}-${m}-${day}`;
}

// True when a risk has a deadline in the past and is not closed.
export function isRiskOverdue(risk: Risk): boolean {
  if (risk.status === RiskStatus.Closed) {
    return false;
  }
  if (!risk.deadline) {
    return false;
  }
  const deadlineMs: number = new Date(risk.deadline).getTime();
  if (Number.isNaN(deadlineMs)) {
    return false;
  }
  return deadlineMs < Date.now();
}

// Milliseconds elapsed since an ISO timestamp (>=0).
export function msSince(iso: string): number {
  if (!iso) {
    return Number.POSITIVE_INFINITY;
  }
  const t: number = new Date(iso).getTime();
  if (Number.isNaN(t)) {
    return Number.POSITIVE_INFINITY;
  }
  return Date.now() - t;
}

// Days elapsed since an ISO timestamp (>=0).
export function daysSince(iso: string): number {
  return Math.floor(msSince(iso) / (24 * 60 * 60 * 1000));
}

// Clone a checkpoint list, resetting every checkpoint to Pending with an empty
// note. Used when starting a new patrol session from a route template.
export function resetCheckpoints(source: Checkpoint[]): Checkpoint[] {
  return source.map((cp: Checkpoint) => {
    return {
      id: cp.id,
      name: cp.name,
      status: CheckpointStatus.Pending,
      note: '',
    } as Checkpoint;
  });
}

