// LocalRepository.ets
//
// Durable local persistence + in-memory collections for Pinankou.
//
// Boundary:
// - CRUD only. No UI, no reactivity, no domain derivations.
// - Persistence backend: @kit.ArkData preferences, storing one JSON blob per
//   collection under a single preference store.
// - After init(context) resolves, all reads are synchronous from memory; writes
//   update memory synchronously and persist asynchronously (fire-and-forget).
// - First-run state is real-empty: no seed data.
//
// If preferences is unavailable at runtime, the repository degrades to
// in-memory-only operation (changes lost on process exit). This fallback is
// acceptable for the current offline-first scope and is logged.

import { preferences } from '@kit.ArkData';
import { common } from '@kit.AbilityKit';
import { hilog } from '@kit.PerformanceAnalysisKit';
import {
  Checkpoint,
  CheckpointStatus,
  Contact,
  Matter,
  PatrolRoute,
  PatrolSession,
  Risk,
  Settings,
} from '../common/Models';

const DOMAIN: number = 0x0501;
const TAG: string = 'PinankouRepo';
const STORE_NAME: string = 'pinankou_store';

const KEY_MATTERS: string = 'matters';
const KEY_RISKS: string = 'risks';
const KEY_CONTACTS: string = 'contacts';
const KEY_ROUTES: string = 'routes';
const KEY_SESSIONS: string = 'sessions';
const KEY_SETTINGS: string = 'settings';

function defaultSettings(): Settings {
  return {
    profileName: '',
    profileRole: '',
    notificationsEnabled: true,
  } as Settings;
}

export class LocalRepository {
  private pref: preferences.Preferences | null = null;
  private ready: boolean = false;

  private matters: Matter[] = [];
  private risks: Risk[] = [];
  private contacts: Contact[] = [];
  private routes: PatrolRoute[] = [];
  private sessions: PatrolSession[] = [];
  private settingsValue: Settings = defaultSettings();

  async init(context: common.Context): Promise<void> {
    try {
      this.pref = await preferences.getPreferences(context, STORE_NAME);
      this.matters = await this.loadList<Matter>(KEY_MATTERS);
      this.risks = await this.loadList<Risk>(KEY_RISKS);
      this.contacts = await this.loadList<Contact>(KEY_CONTACTS);
      this.routes = await this.loadList<PatrolRoute>(KEY_ROUTES);
      this.sessions = await this.loadList<PatrolSession>(KEY_SESSIONS);
      this.settingsValue = await this.loadSettings();
      this.ready = true;
      hilog.info(DOMAIN, TAG, 'repository ready');
    } catch (err) {
      hilog.error(DOMAIN, TAG, 'init failed, running in-memory only: %{public}s', JSON.stringify(err));
      this.settingsValue = defaultSettings();
      this.ready = false;
    }
  }

  isReady(): boolean {
    return this.ready;
  }

  // ---------- Matters ----------

  getMatters(): Matter[] {
    return this.matters;
  }

  getMatter(id: string): Matter | undefined {
    return this.matters.find((m: Matter) => m.id === id);
  }

  upsertMatter(matter: Matter): void {
    const idx: number = this.matters.findIndex((m: Matter) => m.id === matter.id);
    if (idx >= 0) {
      this.matters[idx] = matter;
    } else {
      this.matters.unshift(matter);
    }
    this.persistList<Matter>(KEY_MATTERS, this.matters);
  }

  deleteMatter(id: string): void {
