// StatsService.ets
//
// Pure derivations for the dashboard and statistics board.
//
// Boundary: no side effects, no persistence, no UI. Given the current
// repository state, it returns plain numbers and arrays for the controller
// and (later) the chart shells to render.
//
// Time windowing: "rolling 7 days, grouped by calendar week for display"
// (resolved open question in the spec). The weekly trend produces the most
// recent `weekCount` complete-ish 7-day buckets ending at the current week.

import {
  formatDate,
  isRiskOverdue,
  Matter,
  MatterCategory,
  matterCategoryLabel,
  PatrolSession,
  Risk,
  RiskStatus,
} from '../common/Models';

export interface DashboardStats {
  openRisks: number;
  overdue: number;
  todayPatrols: number;
  closedThisWeek: number;
}

export interface WeeklyTrendPoint {
  week: string; // display label of the bucket start date
  reported: number; // risks whose createdAt falls in this bucket
  closed: number; // risks whose closedAt falls in this bucket
}

export interface CategoryPoint {
  category: string;
  count: number;
}

const DAY_MS: number = 24 * 60 * 60 * 1000;

// Start of the current week (Monday) as a timestamp in ms.
function weekStartMs(now: number): number {
  const date: Date = new Date(now);
  date.setHours(0, 0, 0, 0);
  const dow: number = date.getDay(); // 0 Sun .. 6 Sat
  const offset: number = dow === 0 ? 6 : dow - 1; // days since Monday
  return date.getTime() - offset * DAY_MS;
}

export class StatsService {
  static dashboard(risks: Risk[], sessions: PatrolSession[], weekCount: number = 1): DashboardStats {
    const nowMs: number = Date.now();
    const weekAgoMs: number = nowMs - weekCount * 7 * DAY_MS;
    const todayStart: number = (() => {
      const d: Date = new Date();
      d.setHours(0, 0, 0, 0);
      return d.getTime();
    })();

    let openRisks: number = 0;
    let overdue: number = 0;
    let closedThisWeek: number = 0;
    for (const risk of risks) {
      if (risk.status !== RiskStatus.Closed) {
        openRisks += 1;
      }
      if (isRiskOverdue(risk)) {
        overdue += 1;
      }
      if (risk.status === RiskStatus.Closed && risk.closedAt) {
        const closedMs: number = new Date(risk.closedAt).getTime();
        if (!Number.isNaN(closedMs) && closedMs >= weekAgoMs) {
          closedThisWeek += 1;
        }
      }
    }

    let todayPatrols: number = 0;
    for (const session of sessions) {
      if (!session.completedAt) {
        continue;
      }
      const completedMs: number = new Date(session.completedAt).getTime();
      if (!Number.isNaN(completedMs) && completedMs >= todayStart) {
        todayPatrols += 1;
      }
    }

    return { openRisks, overdue, todayPatrols, closedThisWeek } as DashboardStats;
  }

  static weeklyTrend(risks: Risk[], weekCount: number = 6): WeeklyTrendPoint[] {
    const nowMs: number = Date.now();
    const currentWeekStart: number = weekStartMs(nowMs);
    const buckets: WeeklyTrendPoint[] = [];
    for (let i: number = weekCount - 1; i >= 0; i--) {
      const start: number = currentWeekStart - i * 7 * DAY_MS;
      buckets.push({
        week: formatDate(new Date(start).toISOString()),
        reported: 0,
        closed: 0,
      } as WeeklyTrendPoint);
    }

    const indexFor: (ms: number) => number = (ms: number) => {
      if (Number.isNaN(ms)) {
        return -1;
      }
      const offset: number = Math.floor((ms - currentWeekStart) / (7 * DAY_MS));
      // offset 0 == current week (last bucket). Map into buckets index.
      if (offset < 0 || offset >= weekCount) {
        return -1;
      }
      return weekCount - 1 - (weekCount - 1 - offset); // identity for offset->index
    };

    // Simpler mapping: bucket at index (weekCount-1) is the current week (offset 0).
    const bucketIndex: (ms: number) => number = (ms: number) => {
      if (Number.isNaN(ms)) {
        return -1;
      }
      const offset: number = Math.floor((ms - currentWeekStart) / (7 * DAY_MS));
      if (offset < 0 || offset >= weekCount) {
        return -1;
      }
      return weekCount - 1 - offset;
    };

    for (const risk of risks) {
      const createdMs: number = new Date(risk.createdAt).getTime();
      const ci: number = bucketIndex(createdMs);
      if (ci >= 0) {
        buckets[ci].reported += 1;
      }
      if (risk.closedAt) {
        const closedMs: number = new Date(risk.closedAt).getTime();
        const cli: number = bucketIndex(closedMs);
        if (cli >= 0) {
          buckets[cli].closed += 1;
        }
      }
    }
    // indexFor retained for clarity of intent; reference to avoid unused warning path.
    void indexFor;
    return buckets;
  }

  // Category distribution derived from safety matters (risks have no category
  // field, so matters are the authoritative source for this chart).
  static categoryDistribution(matters: Matter[]): CategoryPoint[] {
    const counts: Map<MatterCategory, number> = new Map<MatterCategory, number>();
    const order: MatterCategory[] = [
      MatterCategory.FireSafety,
      MatterCategory.Electrical,
      MatterCategory.Equipment,
      MatterCategory.Environment,
      MatterCategory.Personnel,
      MatterCategory.Other,
    ];
    for (const cat of order) {
      counts.set(cat, 0);
    }
    for (const matter of matters) {
      const prev: number = counts.get(matter.category) ?? 0;
      counts.set(matter.category, prev + 1);
    }
    const result: CategoryPoint[] = [];
    for (const cat of order) {
      result.push({
        category: matterCategoryLabel(cat),
        count: counts.get(cat) ?? 0,
      } as CategoryPoint);
    }
    return result;
  }

  // Patrol completion = share of checkpoints that are not Pending across all
  // completed sessions. Returns 0-100. 0 when there are no checkpoints.
  static patrolCompletion(sessions: PatrolSession[]): number {
    let total: number = 0;
    let done: number = 0;
    for (const session of sessions) {
      for (const cp of session.checkpoints) {
        total += 1;
        if (cp.status !== 0 /* CheckpointStatus.Pending */) {
          done += 1;
        }
      }
    }
    if (total === 0) {
      return 0;
    }
    return Math.round((done / total) * 100);
  }

  // Overdue ratio = overdue / open risks (0 when no open risks).
  static overdueRatio(risks: Risk[]): number {
    let open: number = 0;
    let overdue: number = 0;
    for (const risk of risks) {
      if (risk.status !== RiskStatus.Closed) {
        open += 1;
      }
      if (isRiskOverdue(risk)) {
        overdue += 1;
      }
    }
    if (open === 0) {
      return 0;
    }
    return Math.round((overdue / open) * 100);
  }
}

