    const counts: Map<MatterCategory, number> = new Map<MatterCategory, number>();
    const order: MatterCategory[] = [
      MatterCategory.FireSafety,
      MatterCategory.Electrical,
      MatterCategory.Equipment,
      MatterCategory.Environment,
      MatterCategory.Personnel,
      MatterCategory.Other,
    ];
    for (const cat of order) {
