// AppController.ets
//
// Singleton view-model / state machine for Pinankou.
//
// Owns the LocalRepository and delegates derivations to StatsService. Exposes
// the ui-behavior event methods and the reactive getters that pages will bind
// to in the visual integration phase.
//
// Reactivity model: @ObservedV2 + @Trace. Scalar/form state and the active
// patrol session are @Trace-tracked; collection mutations bump `dataVersion`
// (also @Trace) so list pages can refresh on change. Active-session updates
// reassign a new object so the trace fires.
//
// Boundary: no UI markup, no direct resource/rawfile access. Phone/message
// actions only invoke system intents (non-goal: real telephony).

import { common, Want } from '@kit.AbilityKit';
import { hilog } from '@kit.PerformanceAnalysisKit';
import {
  Checkpoint,
  CheckpointStatus,
  Contact,
  genId,
  Matter,
  MatterCategory,
  nowISO,
  PatrolRoute,
  PatrolSession,
  resetCheckpoints,
  Risk,
  RiskSeverity,
  RiskStatus,
  Settings,
} from '../common/Models';
import { localRepository, LocalRepository } from '../services/LocalRepository';
import {
  CategoryPoint,
  DashboardStats,
  StatsService,
  WeeklyTrendPoint,
} from '../services/StatsService';

const DOMAIN: number = 0x0502;
const TAG: string = 'PinankouController';

const RISK_FILTER_ALL: string = 'all';
const RISK_FILTER_OPEN: string = 'open';
const RISK_FILTER_IN_PROGRESS: string = 'in-progress';
const RISK_FILTER_CLOSED: string = 'closed';

function statusFromFilter(filter: string): RiskStatus | null {
  if (filter === RISK_FILTER_OPEN) {
    return RiskStatus.Open;
  }
  if (filter === RISK_FILTER_IN_PROGRESS) {
    return RiskStatus.InProgress;
  }
  if (filter === RISK_FILTER_CLOSED) {
    return RiskStatus.Closed;
  }
  return null;
}

@ObservedV2
export class AppController {
  private repo: LocalRepository = localRepository;
  private abilityContext: common.UIAbilityContext | null = null;

  // Reactive scalar / form state.
  @Trace dataVersion: number = 0;
  @Trace selectedRouteId: string = '';
  @Trace activeSession: PatrolSession | null = null;

  @Trace matterQuery: string = '';
  @Trace matterCategoryFilter: number = -1; // -1 == any category

  @Trace riskQuery: string = '';
  @Trace riskStatusFilter: string = RISK_FILTER_ALL;

  @Trace contactQuery: string = '';

  @Trace statsPeriod: string = '7d';

  // Pending edit targets for the add/edit sheets ('' == create).
  @Trace pendingMatterId: string = '';
  @Trace pendingRiskId: string = '';
  @Trace pendingContactId: string = '';

  async init(context: common.UIAbilityContext): Promise<void> {
    this.abilityContext = context;
    await this.repo.init(context);
    this.touch();
  }

  isReady(): boolean {
    return this.repo.isReady();
  }

  // Bump the reactive version so list pages re-render after a mutation.
  private touch(): void {
    this.dataVersion += 1;
  }

  // ---------- Matters ----------

  getMatters(): Matter[] {
    return this.repo.getMatters();
  }

  getMatter(id: string): Matter | undefined {
    return this.repo.getMatter(id);
  }

  getRecentMatters(limit: number = 5): Matter[] {
    return this.repo.getMatters().slice(0, limit);
  }

  // /matters filtered by current query + category filter (used by MattersPage).
  getFilteredMatters(): Matter[] {
    const query: string = this.matterQuery.trim().toLowerCase();
    const cat: number = this.matterCategoryFilter;
    return this.repo.getMatters().filter((m: Matter) => {
      if (cat >= 0 && m.category !== cat) {
        return false;
      }
      if (query.length === 0) {
        return true;
      }
      return this.matchesQuery(m.title, query) ||
        this.matchesQuery(m.location, query) ||
        this.matchesQuery(m.description, query);
    });
  }

  setMatterQuery(value: string): void {
    this.matterQuery = value;
  }

  setMatterCategoryFilter(category: number): void {
    this.matterCategoryFilter = category;
  }

  beginMatterForm(id: string): void {
    this.pendingMatterId = id;
  }

  // save-matter: validate title; returns true on success.
  saveMatter(input: Matter): boolean {
    if (!this.isNotBlank(input.title)) {
      return false;
    }
    const toSave: Matter = {
      id: input.id ? input.id : genId('matter'),
      title: input.title.trim(),
      category: input.category,
      location: input.location.trim(),
      description: input.description.trim(),
      createdAt: input.createdAt ? input.createdAt : nowISO(),
    } as Matter;
    this.repo.upsertMatter(toSave);
    this.pendingMatterId = '';
    this.touch();
    return true;
  }

  cancelMatterForm(): void {
    this.pendingMatterId = '';
  }

  deleteMatter(id: string): void {
    this.repo.deleteMatter(id);
    this.touch();
  }

  // ---------- Risks ----------

  getRisks(): Risk[] {
    return this.repo.getRisks();
  }

  getRisk(id: string): Risk | undefined {
    return this.repo.getRisk(id);
  }

  getRecentRisks(limit: number = 5): Risk[] {
    return this.repo.getRisks().slice(0, limit);
  }

  // /risks filtered by current query + status filter (used by RisksPage).
  getFilteredRisks(): Risk[] {
    const query: string = this.riskQuery.trim().toLowerCase();
    const status: RiskStatus | null = statusFromFilter(this.riskStatusFilter);
    return this.repo.getRisks().filter((r: Risk) => {
      if (status !== null && r.status !== status) {
        return false;
      }
      if (query.length === 0) {
        return true;
      }
      return this.matchesQuery(r.title, query) ||
        this.matchesQuery(r.location, query) ||
        this.matchesQuery(r.responsible, query);
    });
  }

  getRisksByStatus(status: RiskStatus): Risk[] {
    return this.repo.getRisks().filter((r: Risk) => r.status === status);
  }

  setRiskQuery(value: string): void {
    this.riskQuery = value;
  }

  setRiskStatusFilter(filter: string): void {
    this.riskStatusFilter = filter;
  }

  beginRiskForm(id: string): void {
    this.pendingRiskId = id;
  }

  // save-risk: validate title + severity; returns true on success.
  saveRisk(input: Risk): boolean {
    if (!this.isNotBlank(input.title)) {
      return false;
    }
    const previous: Risk | undefined = input.id ? this.repo.getRisk(input.id) : undefined;
    const statusNow: RiskStatus = input.status;
    const closedAt: string = statusNow === RiskStatus.Closed
      ? (previous && previous.closedAt ? previous.closedAt : nowISO())
      : '';
    const toSave: Risk = {
      id: input.id ? input.id : genId('risk'),
      title: input.title.trim(),
      location: input.location.trim(),
      severity: input.severity,
      responsible: input.responsible.trim(),
      deadline: input.deadline,
      status: statusNow,
      description: input.description.trim(),
      createdAt: previous ? previous.createdAt : nowISO(),
      closedAt,
    } as Risk;
    this.repo.upsertRisk(toSave);
    this.pendingRiskId = '';
    this.touch();
    return true;
  }

  cancelRiskForm(): void {
    this.pendingRiskId = '';
  }

  deleteRisk(id: string): void {
    this.repo.deleteRisk(id);
    this.touch();
  }

  // advance-rectification: open -> in-progress -> closed; sets closedAt on close.
  advanceRisk(id: string): void {
    const risk: Risk | undefined = this.repo.getRisk(id);
    if (!risk) {
      return;
    }
    const next: RiskStatus = this.nextStatus(risk.status);
    risk.status = next;
    risk.closedAt = next === RiskStatus.Closed ? nowISO() : '';
    this.repo.upsertRisk(risk);
    this.touch();
  }

  // ---------- Contacts ----------

  getContacts(): Contact[] {
    return this.repo.getContacts();
  }

  getContact(id: string): Contact | undefined {
    return this.repo.getContact(id);
  }

  getFilteredContacts(): Contact[] {
    const query: string = this.contactQuery.trim().toLowerCase();
    if (query.length === 0) {
      return this.repo.getContacts();
    }
    return this.repo.getContacts().filter((c: Contact) => {
      return this.matchesQuery(c.name, query) ||
        this.matchesQuery(c.role, query) ||
        this.matchesQuery(c.phone, query);
    });
  }

  setContactQuery(value: string): void {
    this.contactQuery = value;
  }

  beginContactForm(id: string): void {
    this.pendingContactId = id;
  }

  // save-contact: validate name + phone; returns true on success.
  saveContact(input: Contact): boolean {
    if (!this.isNotBlank(input.name) || !this.isNotBlank(input.phone)) {
      return false;
    }
    const toSave: Contact = {
      id: input.id ? input.id : genId('contact'),
      name: input.name.trim(),
      role: input.role.trim(),
      phone: input.phone.trim(),
      medicalNote: input.medicalNote.trim(),
    } as Contact;
    this.repo.upsertContact(toSave);
    this.pendingContactId = '';
    this.touch();
    return true;
  }

  cancelContactForm(): void {
    this.pendingContactId = '';
  }

  deleteContact(id: string): void {
    this.repo.deleteContact(id);
    this.touch();
  }

  // call-contact: invoke system dialer intent. Returns false if no usable context.
  async callContact(id: string): Promise<boolean> {
    const contact: Contact | undefined = this.repo.getContact(id);
    if (!contact || !this.isNotBlank(contact.phone)) {
      return false;
    }
    return this.launchIntent({ uri: `tel:${contact.phone}` } as Want);
  }

  // message-contact: invoke system messaging intent.
  async messageContact(id: string): Promise<boolean> {
    const contact: Contact | undefined = this.repo.getContact(id);
    if (!contact || !this.isNotBlank(contact.phone)) {
      return false;
    }
    return this.launchIntent({ uri: `sms:${contact.phone}` } as Want);
  }

  // ---------- Patrol ----------

  getRoutes(): PatrolRoute[] {
    return this.repo.getRoutes();
  }

  getRoute(id: string): PatrolRoute | undefined {
    return this.repo.getRoute(id);
  }

  // select-patrol-route
  selectRoute(id: string): void {
    this.selectedRouteId = id;
  }

  getSelectedRoute(): PatrolRoute | undefined {
    return this.selectedRouteId ? this.repo.getRoute(this.selectedRouteId) : undefined;
  }

  // On-device route creation. checkpointNames must contain at least one name.
  createRoute(name: string, checkpointNames: string[]): PatrolRoute | null {
    if (!this.isNotBlank(name) || checkpointNames.length === 0) {
      return null;
    }
    const checkpoints: Checkpoint[] = checkpointNames
      .filter((n: string) => this.isNotBlank(n))
      .map((n: string) => {
        return {
          id: genId('cp'),
          name: n.trim(),
          status: CheckpointStatus.Pending,
          note: '',
        } as Checkpoint;
      });
    if (checkpoints.length === 0) {
      return null;
    }
    const route: PatrolRoute = {
      id: genId('route'),
      name: name.trim(),
      checkpoints,
    } as PatrolRoute;
    this.repo.upsertRoute(route);
    this.selectedRouteId = route.id;
    this.touch();
    return route;
  }

  deleteRoute(id: string): void {
    this.repo.deleteRoute(id);
    if (this.selectedRouteId === id) {
      this.selectedRouteId = '';
    }
    this.touch();
  }

  // start-patrol: requires a selected route with >=1 checkpoint.
  startPatrol(): boolean {
    const route: PatrolRoute | undefined = this.getSelectedRoute();
    if (!route || route.checkpoints.length === 0) {
      return false;
    }
    const session: PatrolSession = {
      id: genId('session'),
      routeId: route.id,
      routeName: route.name,
      startedAt: nowISO(),
      completedAt: '',
      progress: 0,
      checkpoints: resetCheckpoints(route.checkpoints),
    } as PatrolSession;
    this.activeSession = session;
    return true;
  }

  // checkpoint-pass / checkpoint-fail with optional note. Idempotent per checkpoint.
  markCheckpoint(checkpointId: string, status: CheckpointStatus, note: string): void {
    const session: PatrolSession | null = this.activeSession;
    if (!session) {
      return;
    }
    const updated: Checkpoint[] = session.checkpoints.map((cp: Checkpoint) => {
      if (cp.id !== checkpointId) {
        return cp;
      }
      return {
        id: cp.id,
        name: cp.name,
        status,
        note: note,
      } as Checkpoint;
    });
    const progress: number = this.computeProgress(updated);
    this.activeSession = {
      id: session.id,
      routeId: session.routeId,
      routeName: session.routeName,
      startedAt: session.startedAt,
      completedAt: session.completedAt,
      progress,
      checkpoints: updated,
    } as PatrolSession;
  }

  // /patrol/progress for the active session (0-100).
  getActiveProgress(): number {
    const session: PatrolSession | null = this.activeSession;
    return session ? session.progress : 0;
  }

  // submit-patrol: persist the active session (partial patrols are recorded),
  // then clear it. Returns the persisted session id, or '' if none active.
  submitPatrol(): string {
    const session: PatrolSession | null = this.activeSession;
    if (!session) {
      return '';
    }
    const finalSession: PatrolSession = {
      id: session.id,
      routeId: session.routeId,
      routeName: session.routeName,
      startedAt: session.startedAt,
      completedAt: nowISO(),
      progress: session.progress,
      checkpoints: session.checkpoints,
    } as PatrolSession;
    this.repo.upsertSession(finalSession);
    this.activeSession = null;
    this.touch();
    return finalSession.id;
  }

  cancelActivePatrol(): void {
    this.activeSession = null;
  }

  getSessions(): PatrolSession[] {
    return this.repo.getSessions();
  }

  // ---------- Statistics ----------

  getDashboardStats(): DashboardStats {
    return StatsService.dashboard(this.repo.getRisks(), this.repo.getSessions(), 1);
  }

  getWeeklyTrend(): WeeklyTrendPoint[] {
    return StatsService.weeklyTrend(this.repo.getRisks(), 6);
  }

  getCategoryDistribution(): CategoryPoint[] {
    return StatsService.categoryDistribution(this.repo.getMatters());
  }

  getPatrolCompletion(): number {
    return StatsService.patrolCompletion(this.repo.getSessions());
  }

  getOverdueRatio(): number {
    return StatsService.overdueRatio(this.repo.getRisks());
  }

  setStatsPeriod(period: string): void {
    this.statsPeriod = period;
  }

  // export-statistics / export-data: produce a local plain-text summary
  // (no network). Visual phase renders it in a sheet or copies to clipboard.
  buildStatsExportText(): string {
    const dash: DashboardStats = this.getDashboardStats();
    const lines: string[] = [];
    lines.push('平安扣 安全统计');
    lines.push(`待处理隐患: ${dash.openRisks}`);
    lines.push(`逾期隐患: ${dash.overdue}`);
    lines.push(`今日巡检: ${dash.todayPatrols}`);
    lines.push(`本周闭环: ${dash.closedThisWeek}`);
    lines.push(`巡检完成率: ${this.getPatrolCompletion()}%`);
    lines.push(`逾期占比: ${this.getOverdueRatio()}%`);
    return lines.join('\n');
  }

  // ---------- Settings ----------

  getSettings(): Settings {
    return this.repo.getSettings();
  }

  updateSettings(patchName: string, patchRole: string, notifications: boolean): void {
    const current: Settings = this.repo.getSettings();
    this.repo.saveSettings({
      profileName: patchName,
      profileRole: patchRole,
      notificationsEnabled: notifications,
    } as Settings);
    void current;
    this.touch();
  }

  // ---------- Internals ----------

  private computeProgress(checkpoints: Checkpoint[]): number {
    if (checkpoints.length === 0) {
      return 0;
    }
    let done: number = 0;
    for (const cp of checkpoints) {
      if (cp.status !== CheckpointStatus.Pending) {
        done += 1;
      }
    }
    return Math.round((done / checkpoints.length) * 100);
  }

  private nextStatus(value: RiskStatus): RiskStatus {
    if (value === RiskStatus.Open) {
      return RiskStatus.InProgress;
    }
    if (value === RiskStatus.InProgress) {
      return RiskStatus.Closed;
    }
    return RiskStatus.Closed;
  }

  private isNotBlank(value: string): boolean {
    return value !== null && value !== undefined && value.trim().length > 0;
  }

  private matchesQuery(field: string, query: string): boolean {
    return field !== null && field !== undefined && field.toLowerCase().includes(query);
  }

  private async launchIntent(want: Want): Promise<boolean> {
    const ctx: common.UIAbilityContext | null = this.abilityContext;
    if (!ctx) {
      hilog.warn(DOMAIN, TAG, 'no ability context; intent skipped');
      return false;
    }
    try {
      await ctx.startAbility(want);
      return true;
    } catch (err) {
      hilog.error(DOMAIN, TAG, 'startAbility failed: %{public}s', JSON.stringify(err));
      return false;
    }
  }
}

