// LocalRepository.ets
//
// Durable local persistence + in-memory collections for Pinankou.
//
// Boundary:
// - CRUD only. No UI, no reactivity, no domain derivations.
// - Persistence backend: @kit.ArkData preferences, storing one JSON blob per
//   collection under a single preference store.
// - After init(context) resolves, all reads are synchronous from memory; writes
//   update memory synchronously and persist asynchronously (fire-and-forget).
// - First-run state is real-empty: no seed data.
//
// If preferences is unavailable at runtime, the repository degrades to
// in-memory-only operation (changes lost on process exit). This fallback is
// acceptable for the current offline-first scope and is logged.

import { preferences } from '@kit.ArkData';
import { common } from '@kit.AbilityKit';
import { hilog } from '@kit.PerformanceAnalysisKit';
import {
  Contact,
  Matter,
  PatrolRoute,
  PatrolSession,
  Risk,
  Settings,
} from '../common/Models';

const DOMAIN: number = 0x0501;
const TAG: string = 'PinankouRepo';
const STORE_NAME: string = 'pinankou_store';

const KEY_MATTERS: string = 'matters';
const KEY_RISKS: string = 'risks';
const KEY_CONTACTS: string = 'contacts';
const KEY_ROUTES: string = 'routes';
const KEY_SESSIONS: string = 'sessions';
const KEY_SETTINGS: string = 'settings';

function defaultSettings(): Settings {
  return {
    profileName: '',
    profileRole: '',
    notificationsEnabled: true,
  } as Settings;
}

export class LocalRepository {
  private pref: preferences.Preferences | null = null;
  private ready: boolean = false;

  private matters: Matter[] = [];
  private risks: Risk[] = [];
  private contacts: Contact[] = [];
  private routes: PatrolRoute[] = [];
  private sessions: PatrolSession[] = [];
  private settingsValue: Settings = defaultSettings();

  async init(context: common.Context): Promise<void> {
    try {
      this.pref = await preferences.getPreferences(context, STORE_NAME);
      this.matters = await this.loadList<Matter>(KEY_MATTERS);
      this.risks = await this.loadList<Risk>(KEY_RISKS);
      this.contacts = await this.loadList<Contact>(KEY_CONTACTS);
      this.routes = await this.loadList<PatrolRoute>(KEY_ROUTES);
      this.sessions = await this.loadList<PatrolSession>(KEY_SESSIONS);
      this.settingsValue = await this.loadSettings();
      this.ready = true;
      hilog.info(DOMAIN, TAG, 'repository ready');
    } catch (err) {
      hilog.error(DOMAIN, TAG, 'init failed, running in-memory only: %{public}s', JSON.stringify(err));
      this.settingsValue = defaultSettings();
      this.ready = false;
    }
  }

  isReady(): boolean {
    return this.ready;
  }

  // ---------- Matters ----------

  getMatters(): Matter[] {
    return this.matters;
  }

  getMatter(id: string): Matter | undefined {
    return this.matters.find((m: Matter) => m.id === id);
  }

  upsertMatter(matter: Matter): void {
    const idx: number = this.matters.findIndex((m: Matter) => m.id === matter.id);
    if (idx >= 0) {
      this.matters[idx] = matter;
    } else {
      this.matters.unshift(matter);
    }
    this.persistList<Matter>(KEY_MATTERS, this.matters);
  }

  deleteMatter(id: string): void {
    this.matters = this.matters.filter((m: Matter) => m.id !== id);
    this.persistList<Matter>(KEY_MATTERS, this.matters);
  }

  // ---------- Risks ----------

  getRisks(): Risk[] {
    return this.risks;
  }

  getRisk(id: string): Risk | undefined {
    return this.risks.find((r: Risk) => r.id === id);
  }

  upsertRisk(risk: Risk): void {
    const idx: number = this.risks.findIndex((r: Risk) => r.id === risk.id);
    if (idx >= 0) {
      this.risks[idx] = risk;
    } else {
      this.risks.unshift(risk);
    }
    this.persistList<Risk>(KEY_RISKS, this.risks);
  }

  deleteRisk(id: string): void {
    this.risks = this.risks.filter((r: Risk) => r.id !== id);
    this.persistList<Risk>(KEY_RISKS, this.risks);
  }

  // ---------- Contacts ----------

  getContacts(): Contact[] {
    return this.contacts;
  }

  getContact(id: string): Contact | undefined {
    return this.contacts.find((c: Contact) => c.id === id);
  }

  upsertContact(contact: Contact): void {
    const idx: number = this.contacts.findIndex((c: Contact) => c.id === contact.id);
    if (idx >= 0) {
      this.contacts[idx] = contact;
    } else {
      this.contacts.unshift(contact);
    }
    this.persistList<Contact>(KEY_CONTACTS, this.contacts);
  }

  deleteContact(id: string): void {
    this.contacts = this.contacts.filter((c: Contact) => c.id !== id);
    this.persistList<Contact>(KEY_CONTACTS, this.contacts);
  }

  // ---------- Patrol routes ----------

  getRoutes(): PatrolRoute[] {
    return this.routes;
  }

  getRoute(id: string): PatrolRoute | undefined {
    return this.routes.find((r: PatrolRoute) => r.id === id);
  }

  upsertRoute(route: PatrolRoute): void {
    const idx: number = this.routes.findIndex((r: PatrolRoute) => r.id === route.id);
    if (idx >= 0) {
      this.routes[idx] = route;
    } else {
      this.routes.push(route);
    }
    this.persistList<PatrolRoute>(KEY_ROUTES, this.routes);
  }

  deleteRoute(id: string): void {
    this.routes = this.routes.filter((r: PatrolRoute) => r.id !== id);
    this.persistList<PatrolRoute>(KEY_ROUTES, this.routes);
  }

  // ---------- Patrol sessions ----------

  getSessions(): PatrolSession[] {
    return this.sessions;
  }

  upsertSession(session: PatrolSession): void {
    const idx: number = this.sessions.findIndex((s: PatrolSession) => s.id === session.id);
    if (idx >= 0) {
      this.sessions[idx] = session;
    } else {
      this.sessions.unshift(session);
    }
    this.persistList<PatrolSession>(KEY_SESSIONS, this.sessions);
  }

  // ---------- Settings ----------

  getSettings(): Settings {
    return this.settingsValue;
  }

  saveSettings(next: Settings): void {
    this.settingsValue = next;
    this.persistSettings();
  }

  // ---------- Internals ----------

  private async loadList<T>(key: string): Promise<T[]> {
    if (!this.pref) {
      return [];
    }
    try {
      const raw: string = await this.pref.get(key, '') as string;
      if (!raw) {
        return [];
      }
      const parsed: T[] = JSON.parse(raw) as T[];
      return Array.isArray(parsed) ? parsed : [];
    } catch (err) {
      hilog.error(DOMAIN, TAG, 'load %{public}s failed: %{public}s', key, JSON.stringify(err));
      return [];
    }
  }

  private async loadSettings(): Promise<Settings> {
    if (!this.pref) {
      return defaultSettings();
    }
    try {
      const raw: string = await this.pref.get(KEY_SETTINGS, '') as string;
      if (!raw) {
        return defaultSettings();
      }
      const parsed: Settings = JSON.parse(raw) as Settings;
      // Merge with defaults to tolerate schema growth.
      const merged: Settings = defaultSettings();
      merged.profileName = parsed.profileName ? parsed.profileName : '';
      merged.profileRole = parsed.profileRole ? parsed.profileRole : '';
      merged.notificationsEnabled = parsed.notificationsEnabled !== false;
      return merged;
    } catch (err) {
      hilog.error(DOMAIN, TAG, 'load settings failed: %{public}s', JSON.stringify(err));
      return defaultSettings();
    }
  }

  private persistList<T>(key: string, list: T[]): void {
    if (!this.pref) {
      return;
    }
    this.persistJson(key, JSON.stringify(list));
  }

  private persistSettings(): void {
    if (!this.pref) {
      return;
    }
    this.persistJson(KEY_SETTINGS, JSON.stringify(this.settingsValue));
  }

  private persistJson(key: string, value: string): void {
    const pref: preferences.Preferences | null = this.pref;
    if (!pref) {
      return;
    }
    // Fire-and-forget: memory is already updated; persistence is best-effort.
    pref.put(key, value).then(() => {
      pref.flush();
    }).catch((err: Object) => {
      hilog.error(DOMAIN, TAG, 'persist %{public}s failed: %{public}s', key, JSON.stringify(err));
    });
  }
}

// Module-scoped singleton. Initialized once from EntryAbility with the ability context.
export const localRepository: LocalRepository = new LocalRepository();

